{
    "level": "A2–B1",
    "intro": "У цій темі ти навчишся відрізняти <strong>Present Perfect</strong> від <strong>Past Simple</strong> за зв’язком із теперішнім моментом.",
    "rules": [
        {
            "label": "RESULT NOW",
            "color": "emerald",
            "text": "<strong>Present Perfect</strong> показує результат зараз, досвід або період до теперішнього моменту:",
            "example": "I have lost my keys."
        },
        {
            "label": "FINISHED PAST",
            "color": "blue",
            "text": "<strong>Past Simple</strong> показує завершену дію в конкретний минулий час:",
            "example": "I lost my keys yesterday."
        },
        {
            "label": "TIME WORDS",
            "color": "amber",
            "text": "Слова на кшталт <strong>yesterday, last year, ago</strong> тягнуть до Past Simple, а <strong>ever, never, already, yet, just</strong> часто йдуть із Present Perfect.",
            "example": "Have you ever been there? / I went there last year."
        }
    ]
}

{
    "title": "1. Швидке порівняння",
    "intro": "Подивись на різницю в значенні та маркерах часу.",
    "items": [
        {
            "label": "Present Perfect",
            "title": "have / has + V3",
            "subtitle": "I have finished. / She has already left."
        },
        {
            "label": "Past Simple",
            "title": "V2 / did",
            "subtitle": "I finished yesterday. / Did she leave early?"
        },
        {
            "label": "Незавершений період",
            "title": "today / this week / in my life",
            "subtitle": "часто Present Perfect"
        },
        {
            "label": "Завершений час",
            "title": "yesterday / in 2019 / last night / ago",
            "subtitle": "звичайно Past Simple"
        }
    ]
}

{
    "title": "2. Коли брати яку форму",
    "sections": [
        {
            "label": "Present Perfect: результат і досвід",
            "color": "emerald",
            "description": "Ця форма з’єднує минулу дію з <strong>теперішнім результатом</strong> або життєвим досвідом.",
            "examples": [
                {
                    "en": "I have lost my keys, so I cannot open the door.",
                    "ua": "Я загубив ключі, тому не можу відчинити двері."
                },
                {
                    "en": "She has visited Rome three times.",
                    "ua": "Вона була в Римі тричі."
                },
                {
                    "en": "We have lived here for five years.",
                    "ua": "Ми живемо тут уже п’ять років."
                }
            ]
        },
        {
            "label": "Past Simple: завершений момент у минулому",
            "color": "blue",
            "description": "Коли час події <strong>завершений і названий</strong>, потрібен Past Simple.",
            "examples": [
                {
                    "en": "I lost my keys yesterday.",
                    "ua": "Я загубив ключі вчора."
                },
                {
                    "en": "She visited Rome in 2022.",
                    "ua": "Вона відвідала Рим у 2022 році."
                },
                {
                    "en": "We lived there when I was a child.",
                    "ua": "Ми жили там, коли я був дитиною."
                }
            ]
        },
        {
            "label": "Незавершений vs завершений час",
            "color": "amber",
            "description": "<strong>Today / this week / this year</strong> можуть бути ще незавершеними, а <strong>yesterday / last week</strong> уже завершені.",
            "examples": [
                {
                    "en": "I have seen Anna twice this week.",
                    "ua": "Я бачив Анну двічі цього тижня."
                },
                {
                    "en": "I saw Anna twice last week.",
                    "ua": "Я бачив Анну двічі минулого тижня."
                },
                {
                    "en": "Have you eaten today?",
                    "ua": "Ти сьогодні вже їв?"
                }
            ],
            "note": "Питай себе: цей час ще триває чи вже закінчився?"
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Present Perfect з yesterday.",
            "wrong": "I have seen him yesterday.",
            "right": "✅ <span class=\"font-mono\">I saw him yesterday.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Past Simple замість досвіду.",
            "wrong": "Did you ever visit London?",
            "right": "✅ <span class=\"font-mono\">Have you ever visited London?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Past Simple з for / since для періоду до тепер.",
            "wrong": "We lived here for five years. <span class=\"text-slate-500\">(and still live here)</span>",
            "right": "✅ <span class=\"font-mono\">We have lived here for five years.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>Present Perfect</strong> = зв’язок із теперішнім, результат зараз, досвід, період до тепер.",
        "<strong>Past Simple</strong> = завершений момент або період у минулому.",
        "<strong>Yesterday, last, ago, in 2020</strong> майже завжди ведуть до Past Simple.",
        "<strong>Ever, never, already, yet, just, for, since</strong> часто з’являються з Present Perfect.",
        "Ключове питання: час ще пов’язаний із теперішнім чи вже повністю завершений?"
    ]
}

